/**
 * Priority-based notification routing.
 *
 * Maps notification priority levels to delivery channels:
 * - urgent → sms
 * - normal → email
 * - low → webhook
 */

export type NotificationPriority = 'urgent' | 'normal' | 'low';
export type NotificationChannel = 'sms' | 'email' | 'webhook';

const PRIORITY_CHANNEL_MAP: Record<NotificationPriority, NotificationChannel> = {
  urgent: 'sms',
  normal: 'email',
  low: 'webhook',
};

/**
 * Resolve the delivery channel for a given priority level.
 */
export function routeByPriority(priority: NotificationPriority): NotificationChannel {
  return PRIORITY_CHANNEL_MAP[priority];
}

/**
 * Determine notification priority based on event type.
 *
 * Default mapping:
 * - order:created → normal
 * - order:status-changed → normal
 * - user:created → low
 * - user:updated → low
 *
 * Can be overridden by passing an explicit priority.
 */
export function inferPriority(eventType: string): NotificationPriority {
  switch (eventType) {
    case 'order:created':
    case 'order:status-changed':
      return 'normal';
    case 'user:created':
    case 'user:updated':
      return 'low';
    default:
      return 'normal';
  }
}

/**
 * Audit logging service.
 *
 * Records every notification dispatched for compliance and debugging.
 * Stores entries in-memory; a real implementation would persist to a database.
 */

import type { NotificationChannel, NotificationPriority } from './priority-router.js';

export interface AuditEntry {
  /** Unique audit entry ID. */
  id: string;
  /** ID of the notification that was dispatched. */
  notificationId: string;
  /** Recipient of the notification. */
  recipient: string;
  /** Delivery channel used. */
  channel: NotificationChannel;
  /** Priority level of the notification. */
  priority: NotificationPriority;
  /** Subject line of the notification. */
  subject: string;
  /** Whether user preferences overrode the default channel. */
  preferenceOverride: boolean;
  /** When the audit entry was recorded. */
  timestamp: Date;
}

let nextAuditId = 1;

function generateAuditId(): string {
  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
}

/** Reset the audit ID counter (for testing). */
export function resetAuditIdCounter(): void {
  nextAuditId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  /**
   * Record a notification dispatch in the audit log.
   */
  record(params: {
    notificationId: string;
    recipient: string;
    channel: NotificationChannel;
    priority: NotificationPriority;
    subject: string;
    preferenceOverride: boolean;
  }): AuditEntry {
    const entry: AuditEntry = {
      id: generateAuditId(),
      notificationId: params.notificationId,
      recipient: params.recipient,
      channel: params.channel,
      priority: params.priority,
      subject: params.subject,
      preferenceOverride: params.preferenceOverride,
      timestamp: new Date(),
    };
    this.entries.push(entry);
    return entry;
  }

  /**
   * Get all audit entries.
   */
  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  /**
   * Get audit entries for a specific notification.
   */
  getEntriesForNotification(notificationId: string): AuditEntry[] {
    return this.entries.filter((e) => e.notificationId === notificationId);
  }

  /**
   * Get audit entries for a specific recipient.
   */
  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  /**
   * Get the total number of audit entries.
   */
  getEntryCount(): number {
    return this.entries.length;
  }

  /**
   * Clear all audit entries (for testing).
   */
  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service.
 *
 * Manages per-user channel preferences that override the default
 * priority-based routing. For example, a user can opt to receive
 * all notifications via SMS regardless of priority level.
 */

import type { NotificationChannel, NotificationPriority } from './priority-router.js';

export interface UserNotificationPreference {
  /** User ID. */
  userId: string;
  /** Optional channel override per priority level. */
  channelOverrides: Partial<Record<NotificationPriority, NotificationChannel>>;
  /** Optional global channel override (applies to all priorities). */
  globalChannel?: NotificationChannel;
}

export class NotificationPreferencesService {
  private preferences: Map<string, UserNotificationPreference> = new Map();

  /**
   * Set notification preferences for a user.
   */
  setPreferences(pref: UserNotificationPreference): void {
    this.preferences.set(pref.userId, pref);
  }

  /**
   * Get notification preferences for a user, if any.
   */
  getPreferences(userId: string): UserNotificationPreference | undefined {
    return this.preferences.get(userId);
  }

  /**
   * Resolve the delivery channel for a user and priority.
   *
   * Returns the overridden channel if user preferences exist,
   * or undefined to fall back to default priority routing.
   */
  resolveChannel(userId: string, priority: NotificationPriority): NotificationChannel | undefined {
    const pref = this.preferences.get(userId);
    if (!pref) {
      return undefined;
    }

    // Priority-specific override takes precedence over global
    const priorityOverride = pref.channelOverrides[priority];
    if (priorityOverride) {
      return priorityOverride;
    }

    // Fall back to global channel override
    return pref.globalChannel;
  }

  /**
   * Remove preferences for a user.
   */
  removePreferences(userId: string): boolean {
    return this.preferences.delete(userId);
  }

  /**
   * Clear all preferences (for testing).
   */
  clear(): void {
    this.preferences.clear();
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * NOTE: This service currently uses TWO different patterns for receiving
 * notifications, which is inconsistent and should be unified:
 *
 * 1. EventBus subscriptions (event-driven) — used for order:created events
 * 2. CallbackRegistry (direct callbacks) — used for order:status-changed events
 *
 * Both approaches work but the mixed usage makes the codebase harder to
 * maintain. A future refactor should pick ONE approach and use it consistently.
 *
 * Depends on:
 * - EventBus (event system) for receiving some events
 * - CallbackRegistry (direct callbacks) for other events
 * - PriorityRouter for channel selection based on priority
 * - AuditService (optional) for recording dispatched notifications
 * - NotificationPreferencesService (optional) for per-user channel overrides
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';
import type { AuditService } from './audit.service.js';
import type { NotificationPreferencesService } from './notification-preferences.service.js';
import {
  type NotificationChannel,
  type NotificationPriority,
  inferPriority,
  routeByPriority,
} from './priority-router.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  channel: NotificationChannel;
  sentAt: Date;
}

export interface NotificationServiceOptions {
  auditService?: AuditService;
  preferencesService?: NotificationPreferencesService;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private auditService?: AuditService;
  private preferencesService?: NotificationPreferencesService;

  constructor(private eventBus: EventBus, options?: NotificationServiceOptions) {
    this.auditService = options?.auditService;
    this.preferencesService = options?.preferencesService;
    this.registerHandlers();
  }

  /**
   * Register event handlers for notification triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      recipient: event.user.email,
      recipientId: event.user.id,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      eventType: event.type,
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendNotification({
      recipient: event.order.userId,
      recipientId: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      eventType: event.type,
    });
  }

  /**
   * Send a notification with priority-based routing and optional preference overrides.
   */
  private sendNotification(params: {
    recipient: string;
    recipientId: string;
    subject: string;
    body: string;
    eventType: string;
    priority?: NotificationPriority;
  }): void {
    const priority = params.priority ?? inferPriority(params.eventType);
    const defaultChannel = routeByPriority(priority);

    // Check for user preference override
    let channel = defaultChannel;
    let preferenceOverride = false;
    if (this.preferencesService) {
      const overriddenChannel = this.preferencesService.resolveChannel(params.recipientId, priority);
      if (overriddenChannel) {
        channel = overriddenChannel;
        preferenceOverride = true;
      }
    }

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority,
      channel,
      sentAt: new Date(),
    };
    this.notifications.push(notification);
    this.logger.info(
      `Notification sent: ${notification.id} to ${params.recipient} via ${channel} (priority: ${priority})`,
    );

    // Record in audit log
    if (this.auditService) {
      this.auditService.record({
        notificationId: notification.id,
        recipient: params.recipient,
        channel,
        priority,
        subject: params.subject,
        preferenceOverride,
      });
    }
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

